  1	import React, { FC, useEffect, useRef, useState } from 'react';
  2	import { Trans } from 'react-i18next';
  3	
  4	import {
  5	  modelToGroupVersionKind,
  6	  TemplateModel,
  7	  V1Template,
  8	} from '@kubevirt-ui/kubevirt-api/console';
  9	import {
 10	  V1beta1DataSource,
 11	  V1beta1DataVolumeSpec,
 12	} from '@kubevirt-ui/kubevirt-api/containerized-data-importer/models';
 13	import TabModal from '@kubevirt-utils/components/TabModal/TabModal';
 14	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 15	import { K8sResourceCommon, ResourceLink } from '@openshift-console/dynamic-plugin-sdk';
 16	import { Alert, Button, Form, FormGroup, Popover } from '@patternfly/react-core';
 17	
 18	import { SOURCE_TYPES } from '../../utils/constants';
 19	import { editBootSource } from '../editBootSource';
 20	
 21	import useBootSourceEditAffectedTemplates from './hooks/useBootSourceEditAffectedTemplates';
 22	import { SelectSource } from './SelectSource';
 23	import SelectSourceSkeleton from './SelectSourceSkeleton';
 24	import { getDataVolumeSpec } from './utils';
 25	
 26	import './EditBootSourceModal.scss';
 27	
 28	type EditBootSourceModalProps = {
 29	  dataSource: V1beta1DataSource;
 30	  isOpen: boolean;
 31	  obj: V1Template;
 32	  onClose: () => void;
 33	};
 34	
 35	const EditBootSourceModal: FC<EditBootSourceModalProps> = ({
 36	  dataSource,
 37	  isOpen,
 38	  obj,
 39	  onClose,
 40	}) => {
 41	  const { t } = useKubevirtTranslation();
 42	  const [bootSource, setBootSource] = useState<V1beta1DataVolumeSpec>();
 43	  const [loading, setLoading] = useState(false);
 44	
 45	  useEffect(() => {
 46	    setLoading(true);
 47	    getDataVolumeSpec(dataSource)
 48	      .then(setBootSource)
 49	      .finally(() => setLoading(false));
 50	  }, [dataSource]);
 51	
 52	  const affectedTemplates = useBootSourceEditAffectedTemplates(obj);
 53	
 54	  const onSubmit = async () => {
 55	    await editBootSource(dataSource, bootSource);
 56	  };
 57	
 58	  const popoverRef = useRef<HTMLButtonElement>(null);
 59	
 60	  return (
 61	    <>
 62	      <TabModal<K8sResourceCommon>
 63	        headerText={t('Edit boot source reference')}
 64	        isOpen={isOpen}
 65	        obj={obj}
 66	        onClose={onClose}
 67	        onSubmit={onSubmit}
 68	      >
 69	        <Alert className="margin-bottom-md" isInline title={t('Warning')} variant="warning">
 70	          <Trans ns="plugin__kubevirt-plugin">
 71	            Editing the DataSource will affect{' '}
 72	            <Button isInline ref={popoverRef} variant="link">
 73	              all templates
 74	            </Button>{' '}
 75	            that are currently using this DataSource.
 76	          </Trans>
 77	        </Alert>
 78	        <Popover
 79	          bodyContent={(affectedTemplates || []).map((template) => (
 80	            <ResourceLink
 81	              groupVersionKind={modelToGroupVersionKind(TemplateModel)}
 82	              key={template.metadata.uid}
 83	              linkTo={false}
 84	              name={template.metadata.name}
 85	              namespace={template.metadata.namespace}
 86	            />
 87	          ))}
 88	          headerContent={t('Affected templates')}
 89	          triggerRef={popoverRef}
 90	        />
 91	
 92	        <Form>
 93	          <FormGroup fieldId="boot-source-type" isRequired>
 94	            {loading ? (
 95	              <SelectSourceSkeleton />
 96	            ) : (
 97	              <SelectSource
 98	                sourceOptions={[
 99	                  SOURCE_TYPES.pvcSource,
100	                  SOURCE_TYPES.registrySource,
101	                  SOURCE_TYPES.httpSource,
102	                ]}
103	                onSourceChange={setBootSource}
104	                source={bootSource}
105	                sourceLabel={t('Boot source type')}
106	                withSize
107	              />
108	            )}
109	          </FormGroup>
110	        </Form>
111	      </TabModal>
112	    </>
113	  );
114	};
115	
116	export default EditBootSourceModal;

